package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase_noArg() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat result = original.withIgnoreHeaderCase();
        assertNotNull(result);
        assertTrue(result.getIgnoreHeaderCase());
        // Original should remain unchanged
        assertFalse(original.getIgnoreHeaderCase());
        // Should be a new instance
        assertNotSame(original, result);
    }

    @Test
    public void testWithIgnoreHeaderCase_boolean_true() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        Method method = CSVFormat.class.getMethod("withIgnoreHeaderCase", boolean.class);

        CSVFormat result = (CSVFormat) method.invoke(original, true);
        assertNotNull(result);
        assertTrue(result.getIgnoreHeaderCase());
        // Original remains unchanged
        assertFalse(original.getIgnoreHeaderCase());
        assertNotSame(original, result);
    }

    @Test
    public void testWithIgnoreHeaderCase_boolean_false() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        Method method = CSVFormat.class.getMethod("withIgnoreHeaderCase", boolean.class);

        CSVFormat result = (CSVFormat) method.invoke(original, false);
        assertNotNull(result);
        assertFalse(result.getIgnoreHeaderCase());
        // Original remains unchanged
        assertTrue(original.getIgnoreHeaderCase());
        assertNotSame(original, result);
    }
}
